import React, { useEffect, useRef, useState } from 'react';
import { Phone, Mail, MapPin, Send } from 'lucide-react';

export default function Contact() {
  const [visible, setVisible] = useState(false);
  const [form, setForm] = useState({ name: '', email: '', phone: '', interest: '', message: '' });
  const [submitted, setSubmitted] = useState(false);
  const ref = useRef();

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) setVisible(true); },
      { threshold: 0.1 }
    );
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, []);

  const handleSubmit = (e) => {
    e.preventDefault();
    setSubmitted(true);
  };

  const inputStyle = {
    fontFamily: 'var(--font-body)',
    fontSize: '14px',
    fontWeight: 300,
    color: 'var(--white)',
    background: 'rgba(255,255,255,0.04)',
    border: '1px solid rgba(255,255,255,0.12)',
    padding: '16px 20px',
    outline: 'none',
    width: '100%',
    letterSpacing: '0.02em',
    transition: 'border-color 0.3s',
  };

  return (
    <section id="contact" ref={ref} style={{
      padding: '140px 0 80px',
      background: 'linear-gradient(180deg, var(--navy-deep) 0%, var(--navy-deepest) 100%)',
      position: 'relative',
      overflow: 'hidden',
    }}>
      {/* Background decor */}
      <div style={{
        position: 'absolute', right: '-5%', bottom: '10%',
        width: '500px', height: '500px',
        borderRadius: '50%',
        border: '1px solid rgba(201,169,110,0.06)',
        pointerEvents: 'none',
      }} />

      <div className="container">
        <div style={{ textAlign: 'center', marginBottom: '80px' }}>
          <div style={{
            display: 'inline-flex', alignItems: 'center', gap: '12px',
            marginBottom: '24px',
            opacity: visible ? 1 : 0,
            transition: 'opacity 0.7s ease',
          }}>
            <div style={{ width: '32px', height: '1px', background: 'var(--gold)' }} />
            <span style={{ fontFamily: 'var(--font-body)', fontSize: '11px', letterSpacing: '0.3em', color: 'var(--gold)', textTransform: 'uppercase', fontWeight: 500 }}>Get In Touch</span>
            <div style={{ width: '32px', height: '1px', background: 'var(--gold)' }} />
          </div>

          <h2 style={{
            fontFamily: 'var(--font-display)',
            fontSize: 'clamp(44px, 5vw, 72px)',
            fontWeight: 300,
            lineHeight: 1.05,
            color: 'var(--white)',
            letterSpacing: '-0.02em',
            opacity: visible ? 1 : 0,
            transform: visible ? 'translateY(0)' : 'translateY(30px)',
            transition: 'all 0.8s var(--ease-out) 0.2s',
          }}>
            Begin Your<br />
            <em style={{ color: 'var(--gold)', fontStyle: 'italic' }}>Journey</em>
          </h2>
        </div>

        <div style={{
          display: 'grid',
          gridTemplateColumns: '1fr 1.6fr',
          gap: '80px',
        }}>
          {/* Left info */}
          <div style={{
            opacity: visible ? 1 : 0,
            transform: visible ? 'translateY(0)' : 'translateY(30px)',
            transition: 'all 0.8s var(--ease-out) 0.3s',
          }}>
            <p style={{
              fontFamily: 'var(--font-body)',
              fontSize: '15px',
              fontWeight: 300,
              lineHeight: 1.9,
              color: 'var(--white-70)',
              marginBottom: '56px',
            }}>
              Whether you're interested in our upcoming Oman projects, investment opportunities, or simply want to learn more about ADVA — our team is ready to guide you.
            </p>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '32px', marginBottom: '56px' }}>
              {[
                { icon: MapPin, label: 'Location', val: 'Muscat, Sultanate of Oman' },
                { icon: Phone, label: 'Phone', val: '+968 XX XXX XXXX' },
                { icon: Mail, label: 'Email', val: 'info@adva-oman.com' },
              ].map((item, i) => {
                const Icon = item.icon;
                return (
                  <div key={i} style={{ display: 'flex', gap: '20px', alignItems: 'flex-start' }}>
                    <div style={{
                      width: '44px', height: '44px', flexShrink: 0,
                      border: '1px solid rgba(201,169,110,0.25)',
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                    }}>
                      <Icon size={16} color="var(--gold)" />
                    </div>
                    <div>
                      <div style={{ fontFamily: 'var(--font-body)', fontSize: '10px', letterSpacing: '0.25em', color: 'rgba(255,255,255,0.35)', textTransform: 'uppercase', marginBottom: '4px' }}>
                        {item.label}
                      </div>
                      <div style={{ fontFamily: 'var(--font-body)', fontSize: '15px', fontWeight: 300, color: 'var(--white-90)' }}>
                        {item.val}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>

            {/* Egypt office */}
            <div style={{
              padding: '32px',
              background: 'rgba(255,255,255,0.03)',
              border: '1px solid rgba(201,169,110,0.12)',
            }}>
              <div style={{ fontFamily: 'var(--font-body)', fontSize: '10px', letterSpacing: '0.3em', color: 'var(--gold)', textTransform: 'uppercase', marginBottom: '12px' }}>
                Egypt HQ
              </div>
              <div style={{ fontFamily: 'var(--font-body)', fontSize: '14px', fontWeight: 300, color: 'var(--white-70)', lineHeight: 1.7 }}>
                Sheikh Zayed City, West Cairo<br />
                Arab Republic of Egypt<br />
                <span style={{ color: 'var(--gold)', marginTop: '4px', display: 'block' }}>www.adva.com.eg</span>
              </div>
            </div>
          </div>

          {/* Right form */}
          <div style={{
            opacity: visible ? 1 : 0,
            transform: visible ? 'translateY(0)' : 'translateY(30px)',
            transition: 'all 0.8s var(--ease-out) 0.5s',
          }}>
            {submitted ? (
              <div style={{
                padding: '80px 60px',
                background: 'rgba(201,169,110,0.05)',
                border: '1px solid rgba(201,169,110,0.2)',
                textAlign: 'center',
                animation: 'fadeUp 0.6s ease',
              }}>
                <div style={{ fontFamily: 'var(--font-display)', fontSize: '60px', color: 'var(--gold)', marginBottom: '24px' }}>✦</div>
                <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '36px', fontWeight: 300, color: 'var(--white)', marginBottom: '16px' }}>
                  Thank You
                </h3>
                <p style={{ fontFamily: 'var(--font-body)', fontSize: '15px', fontWeight: 300, color: 'var(--white-70)', lineHeight: 1.7 }}>
                  Your enquiry has been received. A member of our team will be in touch within 24 hours.
                </p>
              </div>
            ) : (
              <form onSubmit={handleSubmit}>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '2px', marginBottom: '2px' }}>
                  <input
                    type="text" placeholder="Full Name" required
                    value={form.name} onChange={e => setForm({...form, name: e.target.value})}
                    style={inputStyle}
                    onFocus={e => e.target.style.borderColor = 'rgba(201,169,110,0.5)'}
                    onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.12)'}
                  />
                  <input
                    type="email" placeholder="Email Address" required
                    value={form.email} onChange={e => setForm({...form, email: e.target.value})}
                    style={inputStyle}
                    onFocus={e => e.target.style.borderColor = 'rgba(201,169,110,0.5)'}
                    onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.12)'}
                  />
                </div>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '2px', marginBottom: '2px' }}>
                  <input
                    type="tel" placeholder="Phone Number"
                    value={form.phone} onChange={e => setForm({...form, phone: e.target.value})}
                    style={inputStyle}
                    onFocus={e => e.target.style.borderColor = 'rgba(201,169,110,0.5)'}
                    onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.12)'}
                  />
                  <select
                    value={form.interest} onChange={e => setForm({...form, interest: e.target.value})}
                    style={{...inputStyle, appearance: 'none', cursor: 'pointer'}}
                    onFocus={e => e.target.style.borderColor = 'rgba(201,169,110,0.5)'}
                    onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.12)'}
                  >
                    <option value="" disabled>Area of Interest</option>
                    <option value="residential">Residential Villas</option>
                    <option value="commercial">Commercial Units</option>
                    <option value="investment">Investment Opportunities</option>
                    <option value="partnership">Partnership / Joint Venture</option>
                    <option value="general">General Enquiry</option>
                  </select>
                </div>
                <textarea
                  placeholder="Your Message"
                  rows={6}
                  value={form.message} onChange={e => setForm({...form, message: e.target.value})}
                  style={{...inputStyle, display: 'block', resize: 'vertical', marginBottom: '2px', fontFamily: 'var(--font-body)'}}
                  onFocus={e => e.target.style.borderColor = 'rgba(201,169,110,0.5)'}
                  onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.12)'}
                />

                <button type="submit" style={{
                  width: '100%',
                  padding: '20px',
                  background: 'var(--gold)',
                  border: 'none',
                  fontFamily: 'var(--font-body)',
                  fontSize: '12px',
                  fontWeight: 600,
                  letterSpacing: '0.25em',
                  textTransform: 'uppercase',
                  color: 'var(--navy-deepest)',
                  cursor: 'pointer',
                  display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px',
                  transition: 'all 0.3s',
                }}
                onMouseEnter={e => { e.currentTarget.style.background = 'var(--gold-light)'; e.currentTarget.style.transform = 'translateY(-1px)'; }}
                onMouseLeave={e => { e.currentTarget.style.background = 'var(--gold)'; e.currentTarget.style.transform = 'translateY(0)'; }}>
                  <Send size={14} />
                  Send Enquiry
                </button>
              </form>
            )}
          </div>
        </div>
      </div>

      <style>{`
        @media (max-width: 900px) {
          #contact .container > div:last-child { grid-template-columns: 1fr !important; gap: 60px !important; }
        }
      `}</style>
    </section>
  );
}
